var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이 스타디움에서 경기를 한다고……?","JPN":"このスタジアムで試合を……？","ENG":"This is where the match is going to be held...?","TWN":"在這個體育場裡進行比賽……？"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"엄청 커요! 사람들도 진짜 많고!","JPN":"めちゃくちゃ大きいです！　人も多いですし！","ENG":"It's super big! There are so many people!","TWN":"哇！這裡好大！人也超多！"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"여기가 G 스타디움이야. 꿈이 시작되는 곳이지.","JPN":"ここはGスタジアムだ。夢が始まるところさ。","ENG":"This is G Stadium. It's where you take your first step toward your dream.","TWN":"這裡就是G體育場，是我們夢想的起點！"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"이제까지 봤던 경기장과는 많이 다르군.","JPN":"これまで見てきた競技場とはだいぶ違うな。","ENG":"This is vastly different from the grounds we saw up until now.","TWN":"和我之前看過的體育場很不一樣呢。"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카 말대로 여기서부터가 시작이거든요.","JPN":"ライカの言うとおり、ここからが始まりよ。","ENG":"Like Laika said, this is the first proper step.","TWN":"就像萊卡說的那樣，這裡才是真正的開始。"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"본선은 예선과 포인트 최대치부터 달라요. 차원 함선도 기용하니까요.","JPN":"本戦は予選とポイントの最大値から異なるの。次元艦船も起用するから。","ENG":"The elimination round is nothing like the qualifiers. The maximum amount of points is increased, and they even dispatch dimensional ships.","TWN":"決賽和預賽的點數上限不同，還可以使用次元艦船。"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"오디션 방송 같은 거 본 적 있어? 우린 이제 겨우 심사위원들 앞에 선 거야.","JPN":"オーディション番組とか見たことあるか？　私たちは、やっと審査委員の前に立ったんだ。","ENG":"Ever watched an audition before? Now we get to face the actual judges.","TWN":"你看過選秀節目嗎？我們現在才算是真正站到評審面前。"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그, 그렇게 들으니까 단번에 와 닿네요…. 갑자기 긴장돼요.","JPN":"そ、そう聞くと一気に実感が湧きますね……急に緊張してきました。","ENG":"Th-that makes it sound too real... I'm getting anxious now.","TWN":"聽，聽你這麼一說，一下子就有感覺咧……突然好緊張喔。"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_A","text":{"KOREA":"저쪽이다! 어서 가서 찍어!","JPN":"あっちだ！　早く撮れ！","ENG":"There! Take her photo, now!","TWN":"在那邊！快點過去拍照！"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_B","text":{"KOREA":"기자입니다! 잠시만 지나가겠습니다! 좀 비켜 주세요!","JPN":"記者です！　ちょっと通ります！　どいてください！","ENG":"Excuse me, coming through! I'm a reporter! Move aside, please!","TWN":"我是記者！借過！請讓讓！"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"갑자기 무슨 소란이야? 우리 찍으러 왔대?","JPN":"いきなり何の騒ぎなんだ？　私たちの撮影？","ENG":"What's going on? Are they here to take pictures of us?","TWN":"怎麼突然這麼熱鬧？是來拍我們的嗎？"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저희는 안중에도 없어 보이던데요. 저쪽으로 다 몰려갔어요.","JPN":"私たちなど眼中にないみたいよ。みんなあっちに行ったもの。","ENG":"From the looks of it, they don't care who we are. They are all off towards that direction.","TWN":"完全沒把我們看在眼裡呢，一窩蜂衝到那邊去了。"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어쩌면 유명인이 경기를 보러 왔는지도 몰라요! 구경하러 가요!","JPN":"もしかしたら、有名人が試合を見に来たのかもしれません！　行きましょう！","ENG":"Maybe someone famous has come to see the match! Let's go take a peek!","TWN":"說不定是有名人來看比賽！我們去看看吧！"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"혹시 알파트릭스 회장님 아니야?","JPN":"ひょっとして、アルファトリックスの会長じゃない？","ENG":"Maybe it might be the President of Alphatrix?","TWN":"難道是阿爾法崔克斯會長？"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"여기까지 올 만큼 한가한 상황은 아닐 텐데…?","JPN":"ここまで来るほど、暇な状況ではないはずだが……？","ENG":"I don't think she's got time to come all this way...","TWN":"她應該沒閒到有時間來這裡吧……？"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저기 보세요! 기자들이 잔뜩 몰려 있어요!","JPN":"あっちを見てください！　記者さんがいっぱいです！","ENG":"Look there! The reporters are all gathered over there!","TWN":"看那邊！記者都圍在那裡！"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};